    Examples:
        search([4, 1, 2, 2, 3, 1]) == 2
        search([1, 2, 2, 3, 3, 3, 4, 4, 4]) == 3
        search([5, 5, 4, 4, 4]) == -1
    '''
    if not lst:
        return -1

    count = Counter(lst)
    max_n = -1

    for n in sorted(count.keys(), reverse=True):
        if count[n] >= n:
            max_n = n
            break

